import openai
from datetime import datetime, timedelta

client = openai.OpenAI()

def detect_cost_spikes(project_id: str, threshold_usd: float = 5.0) -> list:
    end_date = datetime.utcnow()
    start_date = end_date - timedelta(days=7)

    usage = client.usage.search(
        start_date=start_date.strftime('%Y-%m-%d'),
        end_date=end_date.strftime('%Y-%m-%d'),
        project_ids=[project_id]
    )

    spikes = []
    daily_costs = {}
    for record in usage.data:
        date = record.timestamp.date()
        daily_costs[date] = daily_costs.get(date, 0) + record.cost

    for date, cost in daily_costs.items():
        if cost > threshold_usd:
            spikes.append({
                'date': date,
                'cost': f'${cost:.2f}',
                'alert': f'Cost exceeded ${threshold_usd} threshold'
            })

    return spikes

import openai

client = openai.OpenAI()

def analyze_run_efficiency(thread_id: str, run_id: str) -> dict:
    run = client.beta.threads.runs.retrieve(
        thread_id=thread_id,
        run_id=run_id
    )

    events = client.beta.threads.runs.events.list(
        thread_id=thread_id,
        run_id=run_id,
        limit=100
    )

    tool_calls = 0
    retries = 0
    requires_action = 0

    for event in events.data:
        if event.event == 'tool_call_created':
            tool_calls += 1
        elif event.event == 'run_requires_action':
            requires_action += 1
        elif event.event == 'run_failed' and 'retry' in str(event.data).lower():
            retries += 1

    return {
        'tool_calls': tool_calls,
        'requires_action': requires_action,
        'retries': retries,
        'efficiency_score': 100 - (retries * 25 + (tool_calls - requires_action) * 10),
        'is_inefficient': tool_calls > 5 or retries > 0
    }

