    def __init__(self):
        self.schemas = {
            'get_weather': {
                'type': 'object',
                'properties': {
                    'location': {'type': 'string'},
                    'unit': {'type': 'string', 'enum': ['celsius', 'fahrenheit']}
                },
                'required': ['location']
            }
        }

    def validate_tool_call(self, tool_call):
        schema = self.schemas.get(tool_call.function.name)
        if not schema:
            return False, "Unknown function"

        try:
            args = json.loads(tool_call.function.arguments)
            # Pydantic validation
            class ToolArgs(BaseModel):
                pass  # Dynamic schema

            # Simple JSON schema validation
            for prop, prop_schema in schema['properties'].items():
                if prop in args and not self._validate_value(args[prop], prop_schema):
                    return False, f"Invalid {prop}"
            return True, "Valid"
        except:
            return False, "Invalid JSON"

    def _validate_value(self, value, schema):
        if 'enum' in schema and value not in schema['enum']:
            return False
        return True

