import vex

@vex.hook('openai_run_completed')
def optimize_assistant_costs(event: dict) -> dict:
    thread_id = event['data']['thread_id']
    run_id = event['data']['id']

    # Run cost optimization checks
    bloat_check = detect_thread_bloat(thread_id)
    run_analysis = analyze_run_efficiency(thread_id, run_id)

    actions = []

    if bloat_check['is_bloated']:
        truncate_thread_context(thread_id)
        actions.append('truncated_thread')

    if run_analysis['is_inefficient']:
        actions.append('flagged_inefficient_run')
        vex.alert(
            title='Cost Optimization Alert',
            message=f'Inefficient run detected: {run_analysis["efficiency_score"]}',
            metadata={'thread_id': thread_id, 'run_id': run_id}
        )

    return {
        'status': 'optimized',
        'actions_taken': actions,
        'savings_estimate': len(actions) * 2.5  # $ per action
    }

